}

type ClientCache struct {
	mu      sync.RWMutex
	clients map[string]dynamic.Interface
	cap     int
}

func NewClientCache(cap int) *ClientCache {
	return &ClientCache{
		clients: make(map[string]dynamic.Interface),
		cap:     cap,
	}
}

func (c *ClientCache) Get(key string) (dynamic.Interface, bool) {
	c.mu.RLock()
