func (tc *TokenCache) Get(token string) (string, bool) {
	tc.mu.RLock()
	defer tc.mu.RUnlock()
	entry, ok := tc.tokens[token]
	if !ok {
		return "", false
	}
	if time.Since(entry.lastAccess) > tc.ttl {
		return "", false
	}
	entry.lastAccess = time.Now()
	return entry.username, true
}

func (tc *TokenCache) Set(token, username string) {
	tc.mu.Lock()
	defer tc.mu.Unlock()
	tc.tokens[token] = &tokenEntry{
		username:   username,
		lastAccess: time.Now(),
	}
}

type SandboxReconciler struct {
	k8sClient *K8sClient
	store     store.Store
	watchers  map[types.NamespacedName]chan struct{}
	mu        sync.RWMutex
}

func NewSandboxReconciler(k8sClient *K8sClient, store store.Store) *SandboxReconciler {
	return &SandboxReconciler{
		k8sClient: k8sClient,
		store:     store,
		watchers:  make(map[types.NamespacedName]chan struct{}),
	}
}

func (r *SandboxReconciler) WatchSandboxOnce(namespace, name string) <-chan struct{} {
	key := types.NamespacedName{Namespace: namespace, Name: name}
	ch := make(chan struct{}, 1)

	r.mu.Lock()
	r.watchers[key] = ch
	r.mu.Unlock()

	return ch
}

func (r *SandboxReconciler) NotifySandboxRunning(namespace, name string) {
	key := types.NamespacedName{Namespace: namespace, Name: name}

	r.mu.RLock()
	ch, ok := r.watchers[key]
	r.mu.RUnlock()

	if ok {
		select {
		case ch <- struct{}{}:
		default:
		}
	}
}

func (r *SandboxReconciler) Reconcile(ctx context.Context, req types.NamespacedName) error {
	sandbox, err := r.k8sClient.dynamicClient.Resource(SandboxGVR).Namespace(req.Namespace).Get(ctx, req.Name, metav1.GetOptions{})
	if err != nil {
		if errors.IsNotFound(err) {
			return nil
		}
		return err
	}

	status := sandbox.Object["status"]
	if status == nil {
		return nil
	}

	statusMap, ok := status.(map[string]interface{})
	if !ok {
		return nil
	}

	conditions, ok := statusMap["conditions"].([]interface{})
	if !ok {
		return nil
	}

	for _, c := range conditions {
		cond, ok := c.(map[string]interface{})
		if !ok {
			continue
		}
		if cond["type"] == "Ready" && cond["status"] == "True" {
			r.NotifySandboxRunning(req.Namespace, req.Name)
			break
		}
	}

	return nil
}

