)

type ErrorResponse struct {
	Message string `json:"message"`
}

type Config struct {
	Port             string
	RuntimeClassName string
	EnableTLS        bool
	TLSCert          string
	TLSKey           string
	EnableAuth       bool
}

type Server struct {
	config            *Config
	router            *gin.Engine
